{
  "day": "1",
  "heading": "Reach the Indiahikes Jungle Line Campus at Manali",
  "sub_heading": "Reporting Time: 3 pm | Location: Beas Bridge, Manali",
  "details": "Pick-up will be arranged from Beas Bridge, Manali to Indiahikes Jungle Line Campus at 3 pm.\nNote: The cost is ₹500 (additional 5% GST) per trekker one way from Manali (Beas Bridge) to Indiahikes Jungle Line Campus (₹1000 for both onward and return journeys). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "2",
  "heading": "Drive from Indiahikes Campus to Rumsu. Trek from Rumsu to Ghan Kuradi",
  "sub_heading": "Drive Distance: 9 km | Drive Duration:  25 minutes | Trek Distance:  3 km | Trek Duration:  3 hours | Altitude Gain:  6,745 ft to 8,930 ft",
  "details": "You will be taking a shared cab from Indiahikes campus to Rumsu. The fare of this ride is included in the trek fee."
}

{
  "day": "3",
  "heading": "Trek from Ghan Kuradi to Chaklani via Naya Tapru",
  "sub_heading": "Trek Distance: 4 km  | Trek Duration: 4 hours | Altitude Gain: 8,930 ft to 11,368 ft",
  "details": ""
}

{
  "day": "4",
  "heading": "Trek from Chaklani to Chandrakhani Pass Top and back to Naya Tapru",
  "sub_heading": "Trek Distance:  9.5 km  | Trek Duration: 10 hours  | Altitude Gain/Loss: 11,368 ft to 10,430 ft via 12,185 ft",
  "details": ""
}

{
  "day": "5",
  "heading": "Trek from Naya Tapru to Rumsu. Drive back to Indiahikes Jungle Line Campus at Manali.",
  "sub_heading": "Drive Distance: 9 km | Drive Duration:  25 minutes  |  Trek Distance:  4.8 km  |  Trek Duration:  5 hours  |  Altitude Loss:  10,430 ft to 6,745 ft",
  "details": "Note: The cost is ₹500 (additional 5% GST) per trekker one way to Manali (Beas Bridge) from Indiahikes Jungle Line Campus (₹1000 for both onward and return journeys). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek."
}
